import machine
import usocket as socket
from microcoapy import CoAP, Resource, RequestHandler

# Create a CoAP server instance
server = CoAP()

# Define resources
class SensorTemp(Resource):
    def render_get(self, request):
        # Simulate temperature reading
        return b"25"

class ActuatorLight(Resource):
    def render_put(self, request):
        # Turn on/off light based on PUT request payload
        if request.payload == b'1':
            machine.Pin(2, machine.Pin.OUT).value(1)
        else:
            machine.Pin(2, machine.Pin.OUT).value(0)

# Create resources
server.add_resource('/sensors/temp', SensorTemp())
server.add_resource('/actuators/light', ActuatorLight())

# Define request handler
class RequestHandler(RequestHandler):
    def handle_request(self, request):
        # Handle GET/PUT requests for resources
        if request.uri.path == '/sensors/temp':
            return self.server.resources['/sensors/temp'].render_get(request)
        elif request.uri.path == '/actuators/light':
            return self.server.resources['/actuators/light'].render_put(request)

# Set up secure CoAP server using DTLS
server.set_dtls()

# Start the CoAP server
server.start(5683)  # Use port 5683 for CoAP

print("CoAP Server started on port 5683")